import{_ as e,o,c as d,ag as a,ah as r}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"技能","description":"","frontmatter":{},"headers":[],"relativePath":"settings/skills.md","filePath":"settings/skills.md"}'),s={name:"settings/skills.md"};function n(l,t,i,c,h,g){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="技能" tabindex="-1">技能 <a class="header-anchor" href="#技能" aria-label="Permalink to &quot;技能&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏 → <strong>设置</strong> → <strong>技能</strong></p><p>技能（Skill）是预置的专项工作流，本质上是存储在特定路径的 Markdown 提示词文件。在对话中可通过 <code>/</code> 命令面板按名称调用，由模型按照技能文件中的指引执行专项任务。</p><p>本页管理各 CLI 各自的技能列表，通过顶部 <strong>Claude | Codex | OpenCode</strong> 切换栏分别维护（OpenCode 家族自 v0.9.0 起纳入）。</p><blockquote><p>Claude 模式下技能通过 <code>/</code> 命令面板调用，详见 <a href="/docs/features/slash-commands.html">斜杠命令</a>；Codex 模式下技能文件由 Codex CLI 直接加载，模型会根据技能的名称与描述自动判断是否调用，也可在 <code>/</code> 命令面板中显式选中；OpenCode 模式的技能来自与 Claude 共享的技能目录及 OpenCode 自有目录，启用开关控制其对 OpenCode 是否生效。</p></blockquote><p><img src="'+r+'" alt="技能设置页面，列表展示已有技能的名称、作用域标签和描述，右侧显示启用开关"></p><hr><h2 id="技能列表" tabindex="-1">技能列表 <a class="header-anchor" href="#技能列表" aria-label="Permalink to &quot;技能列表&quot;">​</a></h2><p>列表中每条技能记录显示：</p><ul><li><strong>名称</strong> — 技能标识，即在 <code>/</code> 面板中输入的名称</li><li><strong>作用域标签</strong> — 蓝色 <strong>用户</strong>、绿色 <strong>工作区</strong> 或紫色 <strong>Plugin</strong>（来自插件提供的内置技能）</li><li><strong>描述</strong> — 技能用途的一句话说明</li><li><strong>启用开关</strong>（Claude / OpenCode 模式下显示）— 即时启用或禁用；禁用后该技能从 <code>/</code> 面板中隐藏</li></ul><p>点击列表中的任意一行可打开 <strong>技能详情</strong> 弹窗，查看技能的名称、描述、作用域、状态和文件路径。</p><hr><h2 id="作用域说明" tabindex="-1">作用域说明 <a class="header-anchor" href="#作用域说明" aria-label="Permalink to &quot;作用域说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>作用域</th><th>存储位置</th><th>说明</th></tr></thead><tbody><tr><td><strong>用户</strong></td><td>用户级配置目录</td><td>跨工作区生效</td></tr><tr><td><strong>工作区</strong></td><td>工作区目录下</td><td>仅对当前工作区生效</td></tr><tr><td><strong>Plugin</strong>（界面原文）</td><td>由插件附带</td><td>来自已安装插件，附加 <strong>项目</strong> 或 <strong>用户</strong> 子作用域标签</td></tr></tbody></table><hr><h2 id="创建技能" tabindex="-1">创建技能 <a class="header-anchor" href="#创建技能" aria-label="Permalink to &quot;创建技能&quot;">​</a></h2><h3 id="claude-模式" tabindex="-1">Claude 模式 <a class="header-anchor" href="#claude-模式" aria-label="Permalink to &quot;Claude 模式&quot;">​</a></h3><p>点击列表顶部的 <strong>创建技能</strong> 按钮：</p><ul><li>若已关联工作区任务，将自动在对话面板中启动一个新任务，并调用 <code>skill-creator</code> 技能引导你逐步填写技能内容</li><li>若未关联工作区任务，按钮不可点击，悬停提示&quot;需先选中某个工作区的任务&quot;</li></ul><h3 id="codex-模式" tabindex="-1">Codex 模式 <a class="header-anchor" href="#codex-模式" aria-label="Permalink to &quot;Codex 模式&quot;">​</a></h3><p>点击 <strong>创建技能</strong> 按钮后弹出 <strong>新建 Codex 技能</strong> 对话框，填写以下字段后点击 <strong>创建</strong>：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>技能标识，如 <code>pdf-processing</code></td></tr><tr><td><strong>描述</strong></td><td>一句话说明技能用途与触发时机</td></tr></tbody></table><h3 id="opencode-模式" tabindex="-1">OpenCode 模式 <a class="header-anchor" href="#opencode-模式" aria-label="Permalink to &quot;OpenCode 模式&quot;">​</a></h3><p>OpenCode 模式<strong>不提供新建入口</strong>（v0.9.0 起）——它天生与 Claude 共享技能目录，因此本页只<strong>列出</strong>这些技能并提供启用开关，不重复创建。若要新增技能，在 <strong>Claude</strong> 模式下创建即可，OpenCode 会自动共享。</p><hr><h2 id="在对话中使用技能" tabindex="-1">在对话中使用技能 <a class="header-anchor" href="#在对话中使用技能" aria-label="Permalink to &quot;在对话中使用技能&quot;">​</a></h2><p>Claude 模式下，在输入框输入 <code>/</code> 打开命令面板，技能会与插件命令一同列出，带有琥珀色的 <code>skill</code> 类型标识。输入技能名称可快速筛选并选中。</p><p>Codex 模式下无需手动触发：技能文件存放在 Codex CLI 识别的目录中（用户级 <code>~/.codex/skills/</code>，项目级 <code>&lt;工作区&gt;/.codex/skills/</code>，以及已安装插件附带的技能），由 Codex CLI 直接加载，模型根据每个技能的名称与描述自动判断是否使用；你也可以在 <code>/</code> 命令面板中显式选中某个技能随消息发送。Codex 模式没有逐技能的启用开关。</p><p>OpenCode 模式下，技能来自与 Claude 共享的加载根及 OpenCode 自有目录。本页的启用开关会写入应用托管的 OpenCode 配置（<code>permission.skill</code>，并保留其中的供应商 / MCP 段），控制每个技能对 OpenCode 是否生效；已启用的技能也会显示在 <code>/</code> 命令面板中。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/bots.html">机器人渠道</a> — 把微信或飞书接入 LoongCode，远程驱动任务</li><li><a href="/docs/features/slash-commands.html">斜杠命令</a> — 了解 <code>/</code> 面板中技能与插件命令的完整呈现方式</li></ul>',32)])])}const C=e(s,[["render",n]]);export{u as __pageData,C as default};
